import * as React from 'react';
import Tabs from '@mui/material/Tabs';
import Tab from '@mui/material/Tab';
import Typography from '@mui/material/Typography';
import Box from '@mui/material/Box';
import NotificationsIcon from '@mui/icons-material/Notifications';
import {styled} from "@mui/material";
import MessageIcon from '@mui/icons-material/Message';
import GradeIcon from '@mui/icons-material/Grade';
import TaskIcon from '@mui/icons-material/Task';
import ArticleIcon from '@mui/icons-material/Article';

interface TabPanelProps {
    children?: React.ReactNode;
    index: number;
    value: number;
}

function TabPanel(props: TabPanelProps) {
    const {children, value, index, ...other} = props;

    return (
        <div
            role="tabpanel"
            hidden={value !== index}
            id={`vertical-tabpanel-${index}`}
            aria-labelledby={`vertical-tab-${index}`}
            {...other}
        >
            {value === index && (
                <Box sx={{p: 3}}>
                    <Typography>{children}</Typography>
                </Box>
            )}
        </div>
    );
}



interface StyledTabProps {
    label: string;
    icon?: string | React.ReactElement;
}

const StyledTab = styled((props: StyledTabProps) => (
    <Tab disableRipple {...props} />
))(({ theme }) => ({
    textTransform: 'none',
    fontWeight: theme.typography.fontWeightRegular,
    fontSize: theme.typography.pxToRem(15),
    marginRight: theme.spacing(1),
    color: 'rgba(255, 255, 255, 0.7)',
    '&.Mui-selected': {
        color: '#fff',
    },
    '&.Mui-focusVisible': {
        backgroundColor: 'rgba(100, 95, 228, 0.32)',
    },
}));


export const VerticalTabs = () => {
    const [value, setValue] = React.useState(0);

    const handleChange = (event: React.SyntheticEvent, newValue: number) => {
        setValue(newValue);
    };

    return (
        <Box
            sx={{flexGrow: 1, display: 'flex', height: "100%", mt: 7}}
        >
            <Tabs
                orientation="vertical"
                value={value}
                onChange={handleChange}
                sx={{borderRight: 1, borderColor: 'divider', width: 130}}
            >
                <StyledTab icon={<NotificationsIcon />} label="Уведомления" />
                <StyledTab icon={<MessageIcon />} label="Сообщения" />
                <StyledTab icon={<GradeIcon />} label="Успеваемость" />
                <StyledTab icon={<TaskIcon />} label="Задачи" />
                <StyledTab icon={<ArticleIcon />} label="Учебные материалы" />

            </Tabs>
            <TabPanel value={value} index={0}>
                Уведомления
            </TabPanel>
            <TabPanel value={value} index={1}>
                Сообщения
            </TabPanel>
            <TabPanel value={value} index={2}>
                Успеваемость
            </TabPanel>
            <TabPanel value={value} index={3}>
                Задачи
            </TabPanel>
            <TabPanel value={value} index={4}>
                Учебные материалы
            </TabPanel>
        </Box>
    );
}