import React, {useState} from 'react';
import {TabPanel} from "../../components/TabPanel";
import {Box, Button, FormControl} from "../../mui";
import {TextInput} from "../../components/TextInput";
import {useAppDispatch, useAppSelector} from "../../store/hooks";
import {useNavigate} from 'react-router-dom';
import {auth_user} from "../../methods/auth_user";
import {setUser} from "../../store/reducers/general-reducer";
import {MySnackBar} from "../../components/MySnackBar";

const stylePaper = {
    p: 2,
    width: 250,
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    margin: '0 auto',
    pb: 5
};

interface AuthorizationType {
    selectTab: number
}


export const Authorization: React.FC<AuthorizationType> = ({selectTab}) => {
    const dispatch = useAppDispatch();
    const navigate = useNavigate();
    const {language} = useAppSelector((state) => state.general);

    const [helperText, setHelperText] = useState<string[]>(['', '']);
    const [settings, setSettings] = useState({
        email: '',
        password: ''
    });

    const [snackBar, setSnackBar] = useState({open: false, color: 'green', message: ''})

    const onBlurEmail = (value: string) => {
        const copyHelperText = [...helperText];
        copyHelperText[0] = '';
        setHelperText(copyHelperText);
        setSettings(prevSettings => ({...prevSettings, email: value}));
    };

    const onBlurPassword = (value: string) => {
        const copyHelperText = [...helperText];
        copyHelperText[1] = '';
        setHelperText(copyHelperText);
        setSettings(prevSettings => ({...prevSettings, password: value}));
    };






    const handleClick = () => {
        // const copyHelperText = [...helperText];
        // if (settings.email === '') {
        //     copyHelperText[0] = language["required_field"];
        // } else if (!settings.email.includes('@')) {
        //     copyHelperText[0] = `${language["missing_symbol"]} "@"`;
        // }
        //
        // if (settings.password === '') {
        //     copyHelperText[1] = language["required_field"];
        // }
        // setHelperText(copyHelperText);
        //
        // (async () => {
        //
        //     if (settings.email !== '' && settings.email.includes('@') && settings.password !== '') {
        //         try {
        //             setSnackBar({open: true, color: 'green', message: `${language["authorization_was_successful"]}`});
        //             const result = await auth_user(settings.email, settings.password);
        //             setTimeout(async () => {
        //                 navigate('/General');
        //             }, 1500);
        //
        //             const {role, password, email, name} = result.user
        //
        //             // dispatch(setUser({role, password, email, name}))
        //
        //         } catch (error: any) {
        //             setSnackBar({open: true, color: 'red', message: error.message})
        //         }
        //     }
        // })();
        navigate('/General');


    }

    const handleCloseSnackbar = () => {
        setSnackBar({...snackBar, open: false});
    }

    return (
        <TabPanel value={selectTab} index={0}>
            <Box sx={stylePaper}>
                <FormControl sx={{marginTop: 2, width: '250px'}}>
                    <TextInput
                        value={settings.email}
                        label={language["mail_address"]}
                        helper={helperText[0]}
                        onBlurHandler={value => onBlurEmail(value.toString())}
                    />
                </FormControl>

                <FormControl sx={{marginTop: 2, width: '250px'}}>
                    <TextInput
                        type="password"
                        value={settings.password}
                        label={language["password"]}
                        helper={helperText[1]}
                        onBlurHandler={value => onBlurPassword(value.toString())}
                    />
                </FormControl>

                <Button variant='outlined' sx={{mt: 5}} onClick={handleClick}>{language["authorization"]}</Button>



                <MySnackBar handleCloseSnackbar={handleCloseSnackbar} open={snackBar.open} message={snackBar.message} color={snackBar.color}/>
            </Box>
        </TabPanel>
    );
};
