import React, {useEffect} from "react";
import {
    AppBar,
    Box,
    Button,
    ButtonGroup,
    FormControlLabel,
    Paper,
    Switch, Toolbar,
} from "../mui";
import WbSunnyIcon from "@mui/icons-material/WbSunny";
import NightlightIcon from "@mui/icons-material/Nightlight";
import {
    changeTheme,
    setCurrentLanguage,
} from "../store/reducers/general-reducer";
import {useAppDispatch, useAppSelector} from "../store/hooks";
import {useTheme} from "@mui/material";
import {saveCurrentLanguage} from "utils/localData";

export const Header = () => {
    const theme = useTheme()

    const {themeApp, currentLanguage} = useAppSelector(
        (state) => state.general
    );
    const dispatch = useAppDispatch();
    const switchHandler = () => {
        dispatch(changeTheme(!themeApp));
    };

    const clickLanguage = (newLanguage: "russian" | "english" ) => {
        saveCurrentLanguage(newLanguage)
        dispatch(setCurrentLanguage(newLanguage))
    }


    return (

        <AppBar position="fixed" sx={{ zIndex: theme => theme.zIndex.drawer + 1 }}>
            <Toolbar variant="dense" sx={{ height: 54 }}>
                <ButtonGroup size="small">
                    <Button
                        variant={currentLanguage === "russian" ? "contained" : "outlined"}
                        onClick={() => clickLanguage("russian")}
                    >
                        RU
                    </Button>
                    <Button
                        variant={currentLanguage === "english" ? "contained" : "outlined"}
                        onClick={() => clickLanguage("english")}
                    >
                        EN
                    </Button>
                </ButtonGroup>
                <FormControlLabel
                    sx={{alignItems: "end", flexGrow: 1, ml: "auto"}}
                    control={<Switch onChange={switchHandler} checked={themeApp}/>}
                    label={themeApp ? <WbSunnyIcon/> : <NightlightIcon/>}
                />
            </Toolbar>
        </AppBar>
    );
};


