import React from 'react';
import { Snackbar } from '../mui';
import { SnackbarCloseReason } from '@mui/material';

interface MySnackBarTypes {
    handleCloseSnackbar: (
        event: React.SyntheticEvent<any, Event>,
        reason: SnackbarCloseReason
    ) => void;
    open: boolean;
    message: string;
    color: string;
}

export const MySnackBar: React.FC<MySnackBarTypes> = ({
                                                          handleCloseSnackbar,
                                                          open,
                                                          message,
                                                          color,
                                                      }) => {
    return (
        <Snackbar
            open={open}
            autoHideDuration={2000}
            onClose={(event, reason) =>
                handleCloseSnackbar(event as React.SyntheticEvent<any, Event>, reason)
            }
            message={message}
            anchorOrigin={{
                vertical: 'bottom',
                horizontal: 'left',
            }}
            ContentProps={{
                style: {
                    color: 'white',
                    backgroundColor: `${color}`,
                },
            }}
        />
    );
};
