import React, {useEffect} from 'react';
import {useAppDispatch, useAppSelector} from "./store/hooks";
import {createTheme, ThemeProvider} from "@mui/material";
import {deepPurple, orange, teal} from "@mui/material/colors";
import {Paper} from "./mui";
import {Header} from "./components/Header";
import {Login} from "./pages/Login/Login";
import {Routes, Route, useNavigate} from "react-router-dom";
import {General} from "./pages/General/General";
import {loadLanguage, loadTheme, loadUser, saveCurrentLanguage} from "./utils/localData";
import {changeTheme, IUser, setCurrentLanguage, setUser} from "./store/reducers/general-reducer";

function App() {
    const dispatch = useAppDispatch()
    const {themeApp} = useAppSelector(state => state.general);
    const theme = createTheme({
        palette: {
            mode: themeApp ? 'dark' : 'light',

            // primary: {
            //     main: orange[500],
            // },
            background: {
                default: themeApp ? '#212121' : '#fff',
                paper: themeApp ? '#212121' : '#fff',
            },
        },
    });


    const navigate = useNavigate();

    useEffect(() => {
        const getLanguage = loadLanguage()
        if (typeof getLanguage === "string" && (getLanguage === "russian" || getLanguage === "english")) {
            dispatch(setCurrentLanguage(getLanguage))
        } else {
            if (navigator.language === "ru") {
                saveCurrentLanguage("russian")
                dispatch(setCurrentLanguage("russian"))
            } else {
                saveCurrentLanguage("english")
                dispatch(setCurrentLanguage("english"))
            }
        }

        const user = loadUser()
        if (typeof user !== "boolean") {
            dispatch(setUser(user))
        }

        dispatch(changeTheme(loadTheme()))

        navigate('/');

    }, []);


    return (
        <ThemeProvider theme={theme}>
            <Paper sx={{height: '100vh', width: '100vw', borderRadius: '0', overflow: 'hidden'}}>
                <Header/>

                <Routes>
                    <Route path="/" element={<Login/>}/>
                    <Route path="/General" element={<General/>}/>
                </Routes>
            </Paper>
        </ThemeProvider>
    );
}

export default App;
